let class_ = root_element;
let employee;

frappe.db.get_value('Employee', { user_id: frappe.session.user }, 'name')
    .then(r => {
        let values = r.message;
        console.log(values.name);
        employee = values.name;

        const today = frappe.datetime.get_today();
        frappe.db.get_list('Employee Checkin', {
            fields: ['time'],
            filters: {
                employee: employee,
                time: ['>=', today]
            }
        }).then(records => {
            console.log('Check-in Records:', records);

            const checkInTime = records[0]?.time ? new Date(records[0].time) : null;
            const checkOutTime = records[1]?.time ? new Date(records[1].time) : null;

            let totalHours = "-";

            if (checkInTime && checkOutTime) {
                const timeDiff = Math.abs(checkOutTime - checkInTime);
                const hours = Math.floor(timeDiff / (1000 * 60 * 60));
                const minutes = Math.floor((timeDiff % (1000 * 60 * 60)) / (1000 * 60));

                totalHours = `${hours} Hrs and ${minutes} Mins`;
            } else if (checkInTime && !checkOutTime) {
                const currentTime = new Date();

                const timeDiff = Math.abs(currentTime - checkInTime);
                const hours = Math.floor(timeDiff / (1000 * 60 * 60));
                const minutes = Math.floor((timeDiff % (1000 * 60 * 60)) / (1000 * 60));

                totalHours = `${hours} Hrs and ${minutes} Mins`;
            }

            const formattedCheckInDate = checkInTime ? frappe.datetime.str_to_user(checkInTime.toISOString().split('T')[0]) : '-';
            const formattedCheckInTime = checkInTime ? checkInTime.toLocaleTimeString() : '-';

            const formattedCheckOutDate = checkOutTime ? frappe.datetime.str_to_user(checkOutTime.toISOString().split('T')[0]) : '-';
            const formattedCheckOutTime = checkOutTime ? checkOutTime.toLocaleTimeString() : '-';
            class_.content = `
                <div class="time-bar">
                    <div class="time-check-in"></div>
                    <div class="time-check-out"></div>
                </div>
                 <table style="border:1px">
                    <tr>
                    <td colspan="3" style="font-size:15px; text-align:center;">
                    Total Worked Hours:<br><b style="font-size:25px"> ${totalHours}</b>
                    </td>
                    </tr>
                    <tr>
                    <td style="width:40%; text-align:center;">
                    <b>Check In</b><br> ${formattedCheckInDate}<br>
                    ${formattedCheckInTime}
                    </td>
                    <td style="width:20%">
                    <br>
                    </td>
                    <td style="width:40%; text-align:center;">
                    <b>Check Out</b> <br>${formattedCheckOutDate}<br>
                    ${formattedCheckOutTime}
                    </td>

                </table>
            `;
            class_.getElementById('employee-personal-details').innerHTML = class_.content;
        });
    });

