script:
let datetimeContainer = root_element.querySelector('.datetime');
let dateContainer = root_element.querySelector('.date');
let timeContainer = root_element.querySelector('.time');

let daynameElement = root_element.querySelector('#dayname');
let monthElement = root_element.querySelector('#month');
let daynumElement = root_element.querySelector('#daynum');
let yearElement = root_element.querySelector('#year');
let hourElement = root_element.querySelector('#hour');
let minutesElement = root_element.querySelector('#minutes');
let secondsElement = root_element.querySelector('#seconds');
let periodElement = root_element.querySelector('#period');

/* NEW: Analog hands */
let hourHand = root_element.querySelector('#hourHand');
let minuteHand = root_element.querySelector('#minuteHand');
let secondHand = root_element.querySelector('#secondHand');

function updateClock() {
    var now = new Date();

    var dname = now.getDay(),
        mo = now.getMonth(),
        dnum = now.getDate(),
        yr = now.getFullYear(),
        hou = now.getHours(),
        min = now.getMinutes(),
        sec = now.getSeconds(),
        pe = "AM";

    if (hou >= 12) pe = "PM";
    if (hou == 0) hou = 12;
    if (hou > 12) hou = hou - 12;

    Number.prototype.pad = function(digits) {
        return this.toString().padStart(digits, '0');
    };

    var months = [
        "January","February","March","April","May","June",
        "July","August","September","October","November","December"
    ];
    var week = [
        "Sunday","Monday","Tuesday","Wednesday",
        "Thursday","Friday","Saturday"
    ];

    /* DIGITAL UPDATE (UNCHANGED LOGIC) */
    daynameElement.textContent = week[dname];
    monthElement.textContent = months[mo];
    daynumElement.textContent = dnum.pad(2);
    yearElement.textContent = yr;
    hourElement.textContent = hou.pad(2);
    minutesElement.textContent = min.pad(2);
    secondsElement.textContent = sec.pad(2);
    periodElement.textContent = pe;

    /* ANALOG TICK-TICK ROTATION */
    if (hourHand && minuteHand && secondHand) {
        hourHand.style.transform =
            `translateX(-50%) rotate(${(hou * 30) + (min * 0.5)}deg)`;

        minuteHand.style.transform =
            `translateX(-50%) rotate(${min * 6}deg)`;

        secondHand.style.transform =
            `translateX(-50%) rotate(${sec * 6}deg)`;
    }
}

/* START CLOCK */
updateClock();
setInterval(updateClock, 1000);

