frappe.ready(function () {

    setTimeout(() => {

        let root = document; // ✅ safer fallback

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Employee",
                filters: {
                    user_id: frappe.session.user
                },
                fields: ["name"],
                limit_page_length: 1
            },
            callback: function (r) {

                if (r.message && r.message.length > 0) {

                    let emp = r.message[0].name;

                    frappe.call({
                        method: "frappe.client.get_list",
                        args: {
                            doctype: "Salary Structure Assignment",
                            filters: {
                                employee: emp
                            },
                            fields: ["base"],
                            order_by: "from_date desc",
                            limit_page_length: 1
                        },
                        callback: function (res) {

                            let salaryEl = root.querySelector("#emp_salary");

                            if (res.message && res.message.length > 0) {
                                salaryEl.innerText = "₹ " + res.message[0].base;
                            } else {
                                salaryEl.innerText = "No Salary Found";
                            }
                        }
                    });

                } else {
                    root.querySelector("#emp_salary").innerText = "No Employee";
                }

            }
        });

    }, 1000);

});

function ess_formatINR(amount) {
    return "₹ " + parseFloat(amount || 0).toLocaleString("en-IN", {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
    });
}

function ess_get_root() {
    // Find the shadow root containing our elements
    var hosts = document.querySelectorAll("*");
    for (var i = 0; i < hosts.length; i++) {
        if (hosts[i].shadowRoot) {
            var el = hosts[i].shadowRoot.getElementById("earnings-table");
            if (el) return hosts[i].shadowRoot;
        }
    }
    return document;
}

function ess_set_html(root, id, html) {
    var el = root.getElementById ? root.getElementById(id) : root.querySelector("#" + id);
    if (el) el.innerHTML = html;
}

function ess_set_text(root, id, text) {
    var el = root.getElementById ? root.getElementById(id) : root.querySelector("#" + id);
    if (el) el.innerText = text;
}

function ess_load_salary() {
    if (typeof frappe === "undefined" || !frappe.session || !frappe.session.user) {
        setTimeout(ess_load_salary, 500);
        return;
    }

    frappe.call({
        method: "get_my_salary_slip",
        callback: function(r) {
            var data = r.message;
            var root = ess_get_root();

            if (!data || data.error) {
                ess_set_html(root, "earnings-table", '<tr><td colspan="2" class="ess-error-msg">' + (data ? data.error : "Error loading data") + '</td></tr>');
                ess_set_html(root, "deductions-table", '<tr><td colspan="2"></td></tr>');
                return;
            }

            // Period
            // ess_set_html(root, "salary-period",
            //     "Period: <strong>" + data.start_date + "</strong> to <strong>" + data.end_date + "</strong>"
            // );

            // Earnings
            if (data.earnings && data.earnings.length) {
                var eHTML = "";
                data.earnings.forEach(function(row) {
                    eHTML += "<tr><td>" + row.salary_component + "</td><td>" + ess_formatINR(row.amount) + "</td></tr>";
                });
                ess_set_html(root, "earnings-table", eHTML);
            } else {
                ess_set_html(root, "earnings-table", '<tr><td colspan="2" class="ess-loading-row">No earnings found.</td></tr>');
            }

            // Deductions
            if (data.deductions && data.deductions.length) {
                var dHTML = "";
                data.deductions.forEach(function(row) {
                    dHTML += "<tr><td>" + row.salary_component + "</td><td>" + ess_formatINR(row.amount) + "</td></tr>";
                });
                ess_set_html(root, "deductions-table", dHTML);
            } else {
                ess_set_html(root, "deductions-table", '<tr><td colspan="2" class="ess-loading-row">No deductions found.</td></tr>');
            }

            // Totals
            ess_set_text(root, "total-earnings", ess_formatINR(data.total_earnings));
            ess_set_text(root, "total-deductions", ess_formatINR(data.total_deductions));
            ess_set_text(root, "net-pay", ess_formatINR(data.net_pay));
        }
    });
}

setTimeout(ess_load_salary, 800);

