.holiday-box {
  position: relative;
  background: #e0f8e0;  /* light red background */
  border: 1px solid #e0f8e0;
  border-radius: 16px;
  padding: 24px;
     box-shadow: 0 6px 18px rgba(76, 175, 80, 0.3);
  width: 100%;
  max-width: 100%;
  font-family: "Segoe UI", sans-serif;
  margin: 20px 0;
  display: flex;
  flex-direction: column;
  gap: 8px;
  overflow: visible;
  cursor: pointer;
  transition: all 0.3s ease;
}

.holiday-title {
  font-size: 1.5rem;
  color: #1565c0; /* blue color for warning icon + text */
  margin: 0;
  display: flex;
  align-items: center;
  gap: 8px;
  transition: all 0.3s ease;
}

.holiday-box:hover .holiday-title {
  animation: bounceGlow 0.6s ease-in-out forwards;
}

.report-field {
  font-size: 1.1rem;
  color: #333;
  margin: 0;
  word-break: break-word;
}

.hover-effects {
  position: absolute;
  top: 0; left: 0;
  width: 100%; height: 100%;
  pointer-events: none;
  z-index: 1;
}

/* Sparkle and Flower (optional, as you already have) */
.sparkle, .flower {
  position: absolute;
  font-size: 1.2rem;
  opacity: 0.8;
  animation: floatFade 3s infinite ease-in-out;
}

.sparkle::before {
  content: "✨";
}

.flower {
  animation: floatFade 4s infinite ease-in-out;
}

/* Star Burst Container */
.star-burst {
  position: absolute;
  width: 12px;
  height: 12px;
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.2s ease;
  filter: drop-shadow(0 0 6px var(--color));
}

/* Each star point */
.star {
  --distance: 30px; /* how far each star point flies */
  position: absolute;
  top: 50%;
  left: 50%;
  width: 4px;
  height: 12px;
  background: var(--color);
  border-radius: 50% / 20%;
  transform-origin: center bottom;
  transform: rotate(calc(var(--i) * 45deg)) translateY(0);
  opacity: 0;
  filter: drop-shadow(0 0 5px var(--color));
  transition: opacity 0.2s ease;
}

/* Animate star points on hover */
.holiday-box:hover .star-burst {
  opacity: 1;
}

.holiday-box:hover .star-burst .star {
  animation: star-burst 0.8s forwards cubic-bezier(0.4, 0, 0.2, 1);
  animation-delay: calc(var(--i) * 0.05s);
  opacity: 1;
}

@keyframes star-burst {
  0% {
    transform: rotate(calc(var(--i) * 45deg)) translateY(0);
    opacity: 1;
  }
  80% {
    transform: rotate(calc(var(--i) * 45deg)) translateY(calc(-1 * var(--distance)));
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}

@keyframes floatFade {
  0% { transform: translateY(0); opacity: 0; }
  25% { opacity: 1; }
  50% { transform: translateY(-10px); }
  75% { opacity: 1; }
  100% { transform: translateY(0); opacity: 0; }
}

@keyframes bounceGlow {
  0% {
    transform: scale(1);
    text-shadow: none;
  }
  50% {
    transform: scale(1.2);
    text-shadow: 0 0 12px #4fc3f7, 0 0 22px #81d4fa;
  }
  100% {
    transform: scale(1);
    text-shadow: none;
  }
}

